import { gunzipSync, gzipSync, unzipSync } from 'fflate'

import type { Logger } from './logger'
import type { TimeFilters, TimePeriod } from './types'

/**
 * Stack-safe min over a numeric array. `Math.min(...arr)` uses the spread
 * operator which throws `RangeError: Maximum call stack size exceeded` on
 * arrays with > ~64-128k elements (engine-dependent). For polygons digitised
 * from GIS coastlines or hi-res shorelines we hit this ceiling silently.
 * Returns `Infinity` for empty input (matching `Math.min`).
 */
export function arrayMin(arr: ArrayLike<number>): number {
  let m = Number.POSITIVE_INFINITY
  for (let i = 0; i < arr.length; i++) {
    const v = arr[i]
    if (v < m) m = v
  }
  return m
}

/** Stack-safe max — counterpart of `arrayMin`. Returns `-Infinity` for empty. */
export function arrayMax(arr: ArrayLike<number>): number {
  let m = Number.NEGATIVE_INFINITY
  for (let i = 0; i < arr.length; i++) {
    const v = arr[i]
    if (v > m) m = v
  }
  return m
}

/**
 * Convert snake_case or kebab-case to camelCase.
 *
 * @param str - The snake_case or kebab-case string to convert.
 * @returns The camelCase version of the string.
 *
 * @example
 * ```ts
 * toCamelCase('first_name')     // 'firstName'
 * toCamelCase('wind-speed')     // 'windSpeed'
 * ```
 */
export function toCamelCase(str: string): string {
  const parts = str.split(/[-_]/)
  return (
    parts[0] +
    parts
      .slice(1)
      .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
      .join('')
  )
}

/**
 * Convert camelCase or snake_case to kebab-case.
 *
 * @param str - The camelCase or snake_case string to convert.
 * @returns The kebab-case version of the string.
 *
 * @example
 * ```ts
 * toKebabCase('firstName')    // 'first-name'
 * toKebabCase('wind_speed')   // 'wind-speed'
 * ```
 */
export function toKebabCase(str: string): string {
  return str
    .replace(/([a-z])([A-Z])/g, '$1-$2')
    .replace(/_/g, '-')
    .toLowerCase()
}

/**
 * Recursively convert all object keys to kebab-case for API serialization.
 *
 * @param obj - The object whose keys should be converted.
 * @returns A new object with all keys in kebab-case.
 *
 * @example
 * ```ts
 * serializeToKebab({ firstName: 'John', addressLine: '123 Main' })
 * // { 'first-name': 'John', 'address-line': '123 Main' }
 * ```
 */
export function serializeToKebab(obj: any): any {
  if (obj === null || obj === undefined) {
    return obj
  }

  if (Array.isArray(obj)) {
    return obj.map((item) => serializeToKebab(item))
  }

  if (typeof obj === 'object' && obj.constructor === Object) {
    const result: any = {}
    for (const [key, value] of Object.entries(obj)) {
      // Drop null/undefined keys to match Python SDK's
      // `Payload.to_dict(exclude_none=True)`. The Infrared API uses
      // Pydantic with `extra="forbid"` server-side, which rejects
      // explicit `null` values for optional fields where Python would
      // simply omit the key.
      if (value === null || value === undefined) continue
      result[toKebabCase(key)] = serializeToKebab(value)
    }
    return result
  }

  return obj
}

/**
 * Recursively convert all object keys to camelCase.
 *
 * @param obj - The object whose keys should be converted.
 * @returns A new object with all keys in camelCase.
 *
 * @example
 * ```ts
 * deserializeToCamelCase({ 'first-name': 'John', 'address-line': '123 Main' })
 * // { firstName: 'John', addressLine: '123 Main' }
 * ```
 */
export function deserializeToCamelCase(obj: any): any {
  if (obj === null || obj === undefined) {
    return obj
  }

  if (Array.isArray(obj)) {
    return obj.map((item) => deserializeToCamelCase(item))
  }

  if (typeof obj === 'object' && obj.constructor === Object) {
    const result: any = {}
    for (const [key, value] of Object.entries(obj)) {
      result[toCamelCase(key)] = deserializeToCamelCase(value)
    }
    return result
  }

  return obj
}

/**
 * Compress data using gzip and encode as base64.
 * Uses fflate (isomorphic, no node:* imports).
 *
 * @param data - The string data to compress.
 * @returns A base64-encoded gzip string.
 *
 * @example
 * ```ts
 * const compressed = gzipAndEncode('{"key":"value"}')
 * // compressed is a base64 string like "H4sIAAAA..."
 * ```
 */
export function gzipAndEncode(data: string): string {
  const encoder = new TextEncoder()
  const bytes = encoder.encode(data)
  const compressed = gzipSync(bytes)

  // Convert Uint8Array to base64 using TextDecoder-safe approach
  // btoa expects a binary string, so we build it in chunks to avoid stack overflow
  return uint8ArrayToBase64(compressed)
}

/**
 * Decompress base64-encoded gzip data.
 * Uses fflate (isomorphic, no node:* imports).
 *
 * @param data - The base64-encoded gzip string to decompress.
 * @returns The decompressed string.
 *
 * @example
 * ```ts
 * const original = gunzipAndDecode(gzipAndEncode('hello'))
 * // original === 'hello'
 * ```
 */
export function gunzipAndDecode(data: string): string {
  const compressed = base64ToUint8Array(data)
  const decompressed = gunzipSync(compressed)
  return new TextDecoder().decode(decompressed)
}

/**
 * Decompress a base64-encoded compressed file (ZIP or gzip) and extract its content.
 *
 * Decompression wire contract:
 * 1. Try ZIP (fflate unzipSync) first
 * 2. Fallback to GZIP (fflate gunzipSync)
 * 3. Decode decompressed bytes via TextDecoder (never String.fromCharCode on decompressed content)
 * 4. Parse as JSON; if result is a bare array, wrap as { output: array }
 *
 * @param base64String - Base64-encoded compressed data
 * @param fn - Optional transform function applied to the decoded string
 * @returns Parsed JSON content or transformed content if fn is provided
 */
export function decompressString<T>(base64String: string, fn?: (s: string) => T): T {
  const bytes = base64ToUint8Array(base64String)
  let content: string

  try {
    // Try ZIP decompression first
    const unzipped = unzipSync(bytes)
    const fileNames = Object.keys(unzipped)
    if (fileNames.length === 0) {
      throw new Error('Empty ZIP archive')
    }
    content = new TextDecoder().decode(unzipped[fileNames[0]])
  } catch {
    // Fallback to GZIP decompression
    const decompressed = gunzipSync(bytes)
    content = new TextDecoder().decode(decompressed)
  }

  if (fn) {
    return fn(content)
  }

  const parsed = JSON.parse(content)

  // If result is a bare array, wrap as { output: array }
  if (Array.isArray(parsed)) {
    return { output: parsed } as T
  }

  return parsed as T
}

/**
 * Decompress the 'result' field of an API response if it's base64-encoded ZIP/GZIP.
 *
 * @param response - The API response object that may contain a compressed `result` field.
 * @param logger - Optional logger for debug/error messages.
 * @returns The response with its `result` field decompressed, or unchanged if not applicable.
 */
export function decompressResultField<T>(response: T, logger?: Logger): T {
  if (!response || typeof response !== 'object') return response

  const obj = response as Record<string, any>
  if (typeof obj.result === 'string') {
    try {
      logger?.debug('Attempting to decompress result field...')
      const decompressed = decompressString(obj.result)
      logger?.debug('Decompression successful')

      return { ...obj, result: decompressed } as T
    } catch (error) {
      logger?.error(`Failed to decompress result field: ${error}`)
      logger?.debug(`Result field preview: ${obj.result.substring(0, 100)}...`)
      return response
    }
  }

  return response
}

/**
 * Create TimePeriod from TimeFilters object.
 *
 * Mirrors Python SDK's `TimePeriod` model: inclusive start + end with
 * individual month/day/hour fields, serialized to `time-period: { start-month,
 * start-day, start-hour, end-month, end-day, end-hour }` on the wire.
 *
 * The optional `filter.day` / `filter.hour` overrides on the input narrow the
 * window further; if absent, the period's start/end values are used directly.
 *
 * @example
 * ```ts
 * createTimePeriodFromFilters({
 *   period: {
 *     start: { month: 6, day: 1, hour: 8 },
 *     end:   { month: 9, day: 30, hour: 18 },
 *   },
 * })
 * // { startMonth: 6, startDay: 1, startHour: 8, endMonth: 9, endDay: 30, endHour: 18 }
 * ```
 */
export function createTimePeriodFromFilters(timeFilters: TimeFilters): TimePeriod {
  const { period, filter } = timeFilters

  let startHour = period.start.hour
  let endHour = period.end.hour
  if (filter?.hour) {
    const [fStart, fEnd] = filter.hour.split('-').map(Number)
    if (Number.isFinite(fStart)) startHour = fStart
    if (Number.isFinite(fEnd)) endHour = fEnd
  }

  let startDay = period.start.day
  let endDay = period.end.day
  if (filter?.day) {
    const [fStart, fEnd] = filter.day.split('-').map(Number)
    if (Number.isFinite(fStart)) startDay = fStart
    if (Number.isFinite(fEnd)) endDay = fEnd
  }

  return {
    startMonth: period.start.month,
    startDay,
    startHour,
    endMonth: period.end.month,
    endDay,
    endHour,
  }
}

// ---------------------------------------------------------------------------
// Internal base64 <-> Uint8Array helpers (no Buffer, no node:* imports)
// ---------------------------------------------------------------------------

/**
 * Convert a Uint8Array to a base64 string without using Buffer.
 * Uses String.fromCharCode in 32KB chunks (safe for compressed data).
 * Note: this is distinct from the decompression path which uses TextDecoder
 * for potentially huge decompressed grid data.
 */
function uint8ArrayToBase64(bytes: Uint8Array): string {
  const CHUNK_SIZE = 0x8000 // 32KB chunks
  const parts: string[] = []
  for (let i = 0; i < bytes.length; i += CHUNK_SIZE) {
    const chunk = bytes.subarray(i, i + CHUNK_SIZE)
    parts.push(String.fromCharCode(...chunk))
  }
  return btoa(parts.join(''))
}

/**
 * Convert a base64 string to a Uint8Array without using Buffer.
 */
function base64ToUint8Array(base64: string): Uint8Array {
  const binary = atob(base64)
  const bytes = new Uint8Array(binary.length)
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i)
  }
  return bytes
}
